// ── Admin: GET /api/admin/deposits ───────────────────────────────────────────

export const getGetAdminDepositsUrl = (params?: GetAdminDepositsParams) => {
  const normalizedParams = new URLSearchParams();
  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) normalizedParams.append(key, value === null ? 'null' : String(value));
  });
  const stringifiedParams = normalizedParams.toString();
  return stringifiedParams.length > 0 ? `/api/admin/deposits?${stringifiedParams}` : '/api/admin/deposits';
};

export const getAdminDeposits = async (params?: GetAdminDepositsParams, options?: RequestInit): Promise<AdminDeposit[]> =>
  customFetch<AdminDeposit[]>(getGetAdminDepositsUrl(params), { ...options, method: 'GET' });

export const getGetAdminDepositsQueryKey = (params?: GetAdminDepositsParams) =>
  ['/api/admin/deposits', ...(params ? [params] : [])] as const;

